/** Flatten all topics from all domains */
export function getAllTopics(lang) {
  const arr = [];
  DOMAINS.forEach((d) =>
    d.sections.forEach((s) =>
      s.topics.forEach((t) => arr.push({
        ...t,
        domainId: d.id,
        domainColor: d.color,
        domainTitle: lang === 'en' ? d.title : d.titleZh,
        domainTitleEn: d.title,
        domainTitleZh: d.titleZh,
      }))
    )
  );
  return arr;
}
